import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import {
  fetchGroupDetails, fetchGroupPosts, createGroupPost,
  fetchGroupMembers, deleteGroup, leaveGroup,
} from '../redux/thunks/groupThunks';
import { clearCurrentGroup } from '../redux/slices/groupSlice';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import PostCard from '../components/posts/PostCard';
import './GroupHome.css';

const GroupHome = () => {
  const { groupId } = useParams();
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { user } = useSelector((state) => state.auth);
  const { currentGroup, groupPosts, groupMembers, postsLoading, hasMorePosts } = useSelector((state) => state.groups);

  const [postText, setPostText] = useState('');
  const [postImage, setPostImage] = useState(null);
  const [posting, setPosting] = useState(false);
  const [showMembers, setShowMembers] = useState(false);
  const [showMenu, setShowMenu] = useState(false);

  useEffect(() => {
    dispatch(fetchGroupDetails({ groupId }));
    dispatch(fetchGroupPosts({ groupId, skip: 0, limit: 25 }));
    dispatch(fetchGroupMembers({ groupId }));
    return () => { dispatch(clearCurrentGroup()); };
  }, [groupId, dispatch]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const groupName = currentGroup?.groupName || currentGroup?.name || 'Group';
  const groupIcon = getImageUrl(
    currentGroup?.ExtraElements?.profileImage ||
    currentGroup?.groupIcon ||
    currentGroup?.profileImage
  );
  const isAdmin = (currentGroup?.groupAdmin || currentGroup?.admin) === user?._id;

  const handleCreatePost = async (e) => {
    e.preventDefault();
    if (!postText.trim()) return;
    setPosting(true);
    const formData = new FormData();
    formData.append('groupId', groupId);
    formData.append('description', postText.trim());
    if (postImage) formData.append('image', postImage);
    const result = await dispatch(createGroupPost(formData));
    setPosting(false);
    if (!result.error) {
      setPostText('');
      setPostImage(null);
      toast.success('Post created');
    } else {
      toast.error('Failed to create post');
    }
  };

  const handleLoadMore = () => {
    if (!postsLoading && hasMorePosts) {
      dispatch(fetchGroupPosts({ groupId, skip: groupPosts.length, limit: 25 }));
    }
  };

  const handleDeleteGroup = async () => {
    if (!window.confirm(`Delete "${groupName}"? This cannot be undone.`)) return;
    const result = await dispatch(deleteGroup({ groupId }));
    if (!result.error) {
      toast.success('Group deleted');
      navigate('/groups');
    } else {
      toast.error('Failed to delete group');
    }
  };

  const handleLeaveGroup = async () => {
    if (!window.confirm(`Leave "${groupName}"?`)) return;
    const result = await dispatch(leaveGroup({ groupId }));
    if (!result.error) {
      toast.success('Left group');
      navigate('/groups');
    } else {
      toast.error('Failed to leave group');
    }
  };

  return (
    <div className="group-home-page">
      {/* Header */}
      <div className="group-home-header">
        <button className="group-home-back" onClick={() => navigate('/groups')}>←</button>
        <div className="group-home-title-row">
          {groupIcon ? (
            <img src={groupIcon} alt="" className="group-home-icon" />
          ) : (
            <div className="group-home-icon-placeholder">👥</div>
          )}
          <div>
            <h2 className="group-home-name">{groupName}</h2>
            <span className="group-home-member-count">
              {groupMembers.length} member{groupMembers.length !== 1 ? 's' : ''}
            </span>
          </div>
        </div>
        <div className="group-home-menu-wrap">
          <button className="group-home-menu-btn" onClick={() => setShowMenu(!showMenu)}>⋮</button>
          {showMenu && (
            <div className="group-home-dropdown">
              <button onClick={() => { setShowMembers(!showMembers); setShowMenu(false); }}>
                👥 Members
              </button>
              {isAdmin ? (
                <button onClick={() => { handleDeleteGroup(); setShowMenu(false); }} className="group-menu-danger">
                  🗑 Delete Group
                </button>
              ) : (
                <button onClick={() => { handleLeaveGroup(); setShowMenu(false); }} className="group-menu-danger">
                  🚪 Leave Group
                </button>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Description */}
      {currentGroup?.description && (
        <p className="group-home-desc">{currentGroup.description}</p>
      )}

      {/* Members panel */}
      {showMembers && (
        <div className="group-members-panel">
          <h3 className="group-members-title">Members ({groupMembers.length})</h3>
          {groupMembers.map((member) => {
            const m = member?.groupMemberId || member;
            const mName = `${m?.firstName || ''} ${m?.lastName || ''}`.trim() || 'User';
            const mAvatar = getImageUrl(m?.imageURL?.thumbnail || m?.imageURL);
            return (
              <div key={m?._id || Math.random()} className="group-member-item">
                {mAvatar ? (
                  <img src={mAvatar} alt="" className="group-member-avatar" />
                ) : (
                  <div className="group-member-avatar-ph">{mName[0].toUpperCase()}</div>
                )}
                <span className="group-member-name">{mName}</span>
              </div>
            );
          })}
        </div>
      )}

      {/* Create post */}
      <form className="group-post-form" onSubmit={handleCreatePost}>
        <textarea
          className="group-post-input"
          placeholder="Write something to the group..."
          value={postText}
          onChange={(e) => setPostText(e.target.value)}
          rows={2}
        />
        <div className="group-post-actions">
          <label className="group-post-media-btn">
            📷 Photo
            <input type="file" accept="image/*" onChange={(e) => setPostImage(e.target.files?.[0])} hidden />
          </label>
          <button type="submit" className="group-post-submit" disabled={!postText.trim() || posting}>
            {posting ? 'Posting...' : 'Post'}
          </button>
        </div>
      </form>

      {/* Posts feed */}
      <div className="group-posts-feed">
        {postsLoading && groupPosts.length === 0 && (
          <div className="groups-loading"><div className="page-loading-spinner" /></div>
        )}
        {!postsLoading && groupPosts.length === 0 && (
          <div className="groups-empty"><p>No posts in this group yet</p></div>
        )}
        {groupPosts.map((post) => (
          <PostCard key={post._id} post={post} />
        ))}
        {hasMorePosts && groupPosts.length > 0 && (
          <button className="home-load-more" onClick={handleLoadMore} disabled={postsLoading}>
            {postsLoading ? 'Loading...' : 'Load More'}
          </button>
        )}
      </div>
    </div>
  );
};

export default GroupHome;
