import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { likeUnlikePost, deletePost } from '../../redux/thunks/postThunks';
import { toast } from 'react-toastify';
import { NODE_API } from '../../api/config';
import CommentSection from './CommentSection';
import './PostCard.css';

const PostCard = ({ post, showDelete = false }) => {
  const [menuOpen, setMenuOpen] = useState(false);
  const [commentsOpen, setCommentsOpen] = useState(false);
  const { user } = useSelector((state) => state.auth);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const isOwner = user?._id === post?.userId?._id || user?._id === post?.userId;

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const authorName = typeof post?.userId === 'object'
    ? `${post.userId.firstName || ''} ${post.userId.lastName || ''}`.trim()
    : user?.firstName || 'User';

  const authorImage = typeof post?.userId === 'object'
    ? getImageUrl(post.userId.imageURL?.thumbnail || post.userId.imageURL)
    : getImageUrl(user?.imageURL?.thumbnail || user?.imageURL);

  const authorId = typeof post?.userId === 'object' ? post.userId._id : post?.userId;

  const timeAgo = (dateStr) => {
    if (!dateStr) return '';
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    const days = Math.floor(hrs / 24);
    if (days < 7) return `${days}d ago`;
    return new Date(dateStr).toLocaleDateString();
  };

  const handleLike = () => {
    dispatch(likeUnlikePost({ postId: post._id }));
  };

  const handleDelete = async () => {
    if (window.confirm('Delete this post?')) {
      const result = await dispatch(deletePost({ postId: post._id }));
      if (!result.error) {
        toast.success('Post deleted');
      } else {
        toast.error('Failed to delete post');
      }
    }
    setMenuOpen(false);
  };

  return (
    <div className="post-card">
      {/* Header */}
      <div className="post-header">
        <div className="post-author" onClick={() => authorId && navigate(`/user/${authorId}`)}>
          {authorImage ? (
            <img src={authorImage} alt="" className="post-avatar" />
          ) : (
            <div className="post-avatar-placeholder">
              {(authorName[0] || 'U').toUpperCase()}
            </div>
          )}
          <div className="post-author-info">
            <span className="post-author-name">{authorName}</span>
            <span className="post-time">{timeAgo(post?.createdAt)}</span>
          </div>
        </div>
        {isOwner && (
          <div className="post-menu-wrap">
            <button className="post-menu-btn" onClick={() => setMenuOpen(!menuOpen)}>⋮</button>
            {menuOpen && (
              <div className="post-menu-dropdown">
                <button onClick={handleDelete} className="post-menu-item post-menu-delete">Delete</button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Content */}
      {post?.description && (
        <p className="post-description">{post.description}</p>
      )}

      {/* Media */}
      {post?.imageURL?.original && (
        <div className="post-media">
          <img
            src={getImageUrl(post.imageURL.original)}
            alt="Post"
            className="post-image"
          />
        </div>
      )}
      {post?.videoURL && !post?.imageURL?.original && (
        <div className="post-media">
          {post?.videoThumbnailUrl?.original ? (
            <img
              src={getImageUrl(post.videoThumbnailUrl.original)}
              alt="Video thumbnail"
              className="post-image"
            />
          ) : (
            <div className="post-video-placeholder">🎬 Video</div>
          )}
        </div>
      )}

      {/* Actions */}
      <div className="post-actions">
        <button
          className={`post-action-btn ${post?.isLike ? 'liked' : ''}`}
          onClick={handleLike}
        >
          <span className="post-action-icon">{post?.isLike ? '👍' : '👍'}</span>
          <span className="post-action-count">{post?.totalLike || 0}</span>
        </button>
        <button
          className="post-action-btn"
          onClick={() => setCommentsOpen(!commentsOpen)}
        >
          <span className="post-action-icon">💬</span>
          <span className="post-action-count">{post?.totalComment || 0}</span>
        </button>
      </div>

      {/* Comments */}
      {commentsOpen && (
        <CommentSection postId={post._id} />
      )}
    </div>
  );
};

export default PostCard;
